  1вҶ’import type { Routine, ExerciseTemplate, ExerciseTemplateMappingRow, QueueItemRow } from "../types";
  2вҶ’import type { HevyRoutineExercise, HevySet, HevyWorkout, HevyExerciseTemplate } from "../hevy/client";
  3вҶ’
  4вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  5вҶ’// Sets string parser
  6вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  7вҶ’
  8вҶ’/**
  9вҶ’ * Parse a sets string like "3Г—8", "3Г—30 sec", "2Г—45 sec", "3Г—1 min"
 10вҶ’ * into an array of HevySet objects.
 11вҶ’ *
 12вҶ’ * - Patterns containing "sec" or "min" produce duration_seconds sets.
 13вҶ’ * - All other patterns produce reps sets.
 14вҶ’ */
 15вҶ’function parseSetsString(setsStr: string): HevySet[] {
 16вҶ’  // Normalise the multiplication sign вҖ” programs may use Г— (U+00D7) or x
 17вҶ’  const normalised = setsStr.replace(/Г—/g, "x");
 18вҶ’
 19вҶ’  // Match "NxM sec", "NxM min", or "NxM"
 20вҶ’  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
 21вҶ’  if (!match) {
 22вҶ’    // Fallback: return a single normal set with no values
 23вҶ’    return [{ type: "normal", reps: null }];
 24вҶ’  }
 25вҶ’
 26вҶ’  const count = parseInt(match[1], 10);
 27вҶ’  const value = parseFloat(match[2]);
 28вҶ’  const unit = match[3]?.toLowerCase();
 29вҶ’
 30вҶ’  const isDuration = unit === "sec" || unit === "min";
 31вҶ’  const duration_seconds = isDuration
 32вҶ’    ? unit === "min"
 33вҶ’      ? Math.round(value * 60)
 34вҶ’      : Math.round(value)
 35вҶ’    : undefined;
 36вҶ’
 37вҶ’  const sets: HevySet[] = [];
 38вҶ’  for (let i = 0; i < count; i++) {
 39вҶ’    if (isDuration) {
 40вҶ’      sets.push({ type: "normal", reps: null, duration_seconds });
 41вҶ’    } else {
 42вҶ’      const reps = Math.round(value);
 43вҶ’      sets.push({ type: "normal", reps });
 44вҶ’    }
 45вҶ’  }
 46вҶ’  return sets;
 47вҶ’}
 48вҶ’
 49вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 50вҶ’// buildRoutinePayload
 51вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 52вҶ’
 53вҶ’export interface RoutinePayload {
 54вҶ’  title: string;
 55вҶ’  exercises: HevyRoutineExercise[];
 56вҶ’  /** Exercise template IDs from the routine that had no mapping */
 57вҶ’  unmapped: string[];
 58вҶ’}
 59вҶ’
 60вҶ’/**
 61вҶ’ * Build a Hevy routine payload from a program routine + exercise template mappings.
 62вҶ’ * Exercises without a mapping are collected in `unmapped` and omitted from
 63вҶ’ * the payload.
 64вҶ’ */
 65вҶ’export function buildRoutinePayload(
 66вҶ’  routine: Routine,
 67вҶ’  mappings: ExerciseTemplateMappingRow[]
 68вҶ’): RoutinePayload {
 69вҶ’  const mappingMap = new Map(
 70вҶ’    mappings.map((m) => [m.program_template_id, m.hevy_template_id])
 71вҶ’  );
 72вҶ’
 73вҶ’  const exercises: HevyRoutineExercise[] = [];
 74вҶ’  const unmapped: string[] = [];
 75вҶ’
 76вҶ’  for (const exercise of routine.exercises) {
 77вҶ’    const hevyId = mappingMap.get(exercise.exerciseTemplateId);
 78вҶ’    if (!hevyId) {
 79вҶ’      unmapped.push(exercise.exerciseTemplateId);
 80вҶ’      continue;
 81вҶ’    }
 82вҶ’
 83вҶ’    const sets = parseSetsString(exercise.sets);
 84вҶ’
 85вҶ’    exercises.push({
 86вҶ’      exercise_template_id: hevyId,
 87вҶ’      sets,
 88вҶ’      notes: exercise.notes,
 89вҶ’    });
 90вҶ’  }
 91вҶ’
 92вҶ’  return { title: routine.title, exercises, unmapped };
 93вҶ’}
 94вҶ’
 95вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 96вҶ’// buildExerciseTemplatePayload
 97вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 98вҶ’
 99вҶ’export interface ExerciseTemplatePayload {
100вҶ’  title: string;
101вҶ’  exercise_type: string;
102вҶ’  equipment_category: string;
103вҶ’  primary_muscle_group: string;
104вҶ’  other_muscles: string[];
105вҶ’}
106вҶ’
107вҶ’/**
108вҶ’ * Build a Hevy exercise template creation payload from a domain ExerciseTemplate.
109вҶ’ * Pure mapping from domain shape (camelCase) to wire shape (snake_case).
110вҶ’ */
111вҶ’export function buildExerciseTemplatePayload(
112вҶ’  template: ExerciseTemplate
113вҶ’): ExerciseTemplatePayload {
114вҶ’  return {
115вҶ’    title: template.title,
116вҶ’    exercise_type: template.type,
117вҶ’    equipment_category: template.equipmentCategory,
118вҶ’    primary_muscle_group: template.primaryMuscleGroup,
119вҶ’    other_muscles: template.secondaryMuscleGroups ?? [],
120вҶ’  };
121вҶ’}
122вҶ’
123вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
124вҶ’// matchCompletions
125вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
126вҶ’
127вҶ’export interface CompletionMatch {
128вҶ’  queueItemId: number;
129вҶ’  workoutId: string;
130вҶ’}
131вҶ’
132вҶ’/**
133вҶ’ * Match Hevy workouts to queue items by comparing each workout's routine ID
134вҶ’ * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
135вҶ’ * item.
136вҶ’ *
137вҶ’ * Each workout is matched to at most one queue item.
138вҶ’ */
139вҶ’export function matchCompletions(
140вҶ’  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
141вҶ’  workouts: HevyWorkout[],
142вҶ’  getRoutineId: (workout: HevyWorkout) => string | null
143вҶ’): CompletionMatch[] {
144вҶ’  // Build a map: routine_id вҶ’ queue item id
145вҶ’  const routineToItem = new Map<string, number>();
146вҶ’  for (const item of items) {
147вҶ’    if (item.hevy_routine_id) {
148вҶ’      routineToItem.set(item.hevy_routine_id, item.id);
149вҶ’    }
150вҶ’  }
151вҶ’
152вҶ’  const matches: CompletionMatch[] = [];
153вҶ’  const usedItems = new Set<number>();
154вҶ’
155вҶ’  for (const workout of workouts) {
156вҶ’    const routineId = getRoutineId(workout);
157вҶ’    if (!routineId) continue;
158вҶ’
159вҶ’    const itemId = routineToItem.get(routineId);
160вҶ’    if (itemId !== undefined && !usedItems.has(itemId)) {
161вҶ’      matches.push({ queueItemId: itemId, workoutId: workout.id });
162вҶ’      usedItems.add(itemId);
163вҶ’    }
164вҶ’  }
165вҶ’
166вҶ’  return matches;
167вҶ’}
168вҶ’
